import { useState, useCallback } from "react";
import { useTranslation } from "react-i18next";
import { Video, Loader2, Shuffle, Search, Bookmark, BookmarkCheck, BookOpen } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { toast } from "sonner";
import { useSavedRecipes } from "@/hooks/useSavedRecipes";
import { useAuth } from "@/contexts/AuthContext";
import { useNavigate } from "react-router-dom";
import SavedRecipeDetailDialog from "@/components/ai-recipe/SavedRecipeDetailDialog";

const SUPABASE_URL = import.meta.env.VITE_SUPABASE_URL;
const ANON_KEY = import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY;
const LOOKUP_URL = `${SUPABASE_URL}/functions/v1/ai-recipe/lookup-dish`;

interface RecipeResult {
  recipe_name: string;
  recipe_name_en?: string;
  recipe_name_pt?: string;
  image_url?: string;
  steps?: any[];
  [key: string]: any;
}

/** Placeholder shown when no recipe is found yet */
const RecipePlaceholder = () => {
  const { t } = useTranslation();
  return (
    <div className="w-full aspect-video rounded-2xl bg-muted/40 border border-dashed border-border flex flex-col items-center justify-center gap-2 px-4">
      <div className="w-9 h-9 rounded-full bg-primary/10 flex items-center justify-center shrink-0">
        <Video className="h-4 w-4 text-primary/60" />
      </div>
      <p className="text-xs text-muted-foreground text-center">
        {t("aiRecipe.videoGen.placeholderHint", "输入菜名或随机挑选，AI 将为您生成烹饪视频")}
      </p>
    </div>
  );
};

const AIVideoGenerator = () => {
  const { t, i18n } = useTranslation();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [dishName, setDishName] = useState("");
  const [isLookingUp, setIsLookingUp] = useState(false);
  const [recipe, setRecipe] = useState<RecipeResult | null>(null);
  const { saveRecipe, isSaving, savedRecipes } = useSavedRecipes();
  const [saved, setSaved] = useState(false);
  const [showRecipeDialog, setShowRecipeDialog] = useState(false);

  const getDisplayName = (r: RecipeResult) => {
    if (i18n.language === "en" && r.recipe_name_en) return r.recipe_name_en;
    if (i18n.language === "pt" && r.recipe_name_pt) return r.recipe_name_pt;
    return r.recipe_name;
  };

  const isSavedAlready = recipe ? (saved || savedRecipes.some(r => r.recipe_name === recipe.recipe_name)) : false;

  const handleLookup = useCallback(async (random = false) => {
    setIsLookingUp(true);
    setRecipe(null);
    setSaved(false);
    try {
      const resp = await fetch(LOOKUP_URL, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${ANON_KEY}`,
        },
        body: JSON.stringify({
          dish_name: random ? "" : dishName.trim(),
          language: i18n.language,
        }),
      });

      if (!resp.ok) {
        const err = await resp.json().catch(() => ({}));
        throw new Error(err.error || `Error ${resp.status}`);
      }

      const data = await resp.json();
      setRecipe(data.recipe);
      toast.success(t("aiRecipe.videoGen.found", "食谱已找到！"));
    } catch (err: any) {
      console.error("Lookup error:", err);
      toast.error(err.message || t("aiRecipe.videoGen.error", "查询失败，请重试"));
    } finally {
      setIsLookingUp(false);
    }
  }, [dishName, i18n.language, t]);

  const handleSave = async () => {
    if (!user) {
      toast.error(t("auth.loginRequired", "请先登录"));
      navigate("/auth");
      return;
    }
    if (!recipe || isSavedAlready) return;
    try {
      await saveRecipe(recipe as any);
      setSaved(true);
    } catch {
      // error handled in hook
    }
  };

  const showRecipeArea = isLookingUp || !!recipe;

  return (
    <div className="w-full space-y-4">
      {/* Header */}
      <div className="text-center space-y-1">
        <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-primary/10 text-primary text-xs font-medium">
          <Video className="h-3.5 w-3.5" />
          {t("aiRecipe.videoGen.title", "AI 烹饪视频")}
        </div>
        <p className="text-xs text-muted-foreground">
          {t("aiRecipe.videoGen.desc", "输入菜名生成AI烹饪视频，或随机挑选")}
        </p>
      </div>

      {/* Input */}
      <div className="flex gap-2">
        <Input
          value={dishName}
          onChange={(e) => setDishName(e.target.value)}
          placeholder={t("aiRecipe.videoGen.placeholder", "输入菜名，如：红烧肉")}
          className="text-sm h-10"
          onKeyDown={(e) => {
            if (e.key === "Enter" && !isLookingUp) handleLookup(false);
          }}
          disabled={isLookingUp}
        />
        <Button
          size="icon"
          onClick={() => handleLookup(false)}
          disabled={isLookingUp || !dishName.trim()}
          className="h-10 w-10 shrink-0"
        >
          {isLookingUp ? <Loader2 className="h-4 w-4 animate-spin" /> : <Search className="h-4 w-4" />}
        </Button>
        <Button
          size="icon"
          variant="outline"
          onClick={() => handleLookup(true)}
          disabled={isLookingUp}
          className="h-10 w-10 shrink-0"
          title={t("aiRecipe.videoGen.random", "随机挑选")}
        >
          {isLookingUp ? <Loader2 className="h-4 w-4 animate-spin" /> : <Shuffle className="h-4 w-4" />}
        </Button>
      </div>

      {/* Recipe Area */}
      <div
        className={`grid transition-all duration-500 ease-out ${
          showRecipeArea ? "grid-rows-[1fr] opacity-100" : "grid-rows-[0fr] opacity-0"
        }`}
      >
        <div className="overflow-hidden">
          <div className="pt-1">
            {isLookingUp ? (
              <div className="w-full aspect-video rounded-2xl bg-muted/30 flex flex-col items-center justify-center gap-3">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
                <p className="text-sm text-muted-foreground">
                  {dishName.trim()
                    ? t("aiRecipe.videoGen.searching", "正在查找食谱...")
                    : t("aiRecipe.videoGen.randomPicking", "随机挑选中...")}
                </p>
              </div>
            ) : recipe ? (
              <div className="w-full space-y-3">
                {/* Recipe image */}
                {recipe.image_url ? (
                  <div className="relative w-full aspect-video rounded-2xl overflow-hidden">
                    <img
                      src={recipe.image_url}
                      alt={getDisplayName(recipe)}
                      className="w-full h-full object-cover"
                    />
                  </div>
                ) : (
                  <div className="w-full aspect-video rounded-2xl bg-muted/30 flex items-center justify-center">
                    <p className="text-sm text-muted-foreground">
                      {t("aiRecipe.videoGen.noImage", "此食谱暂无图片，无法生成视频")}
                    </p>
                  </div>
                )}

                {/* Recipe name */}
                <p className="text-sm font-medium text-center">{getDisplayName(recipe)}</p>

                {/* Action buttons */}
                <div className="flex gap-2">
                  <Button
                    variant="outline"
                    size="sm"
                    className="gap-1.5 flex-1"
                    onClick={() => setShowRecipeDialog(true)}
                  >
                    <BookOpen className="h-3.5 w-3.5" />
                    {t("aiRecipe.video.viewRecipeWithVideo", "查看食谱 & 生成视频")}
                  </Button>
                  <Button
                    variant={isSavedAlready ? "secondary" : "outline"}
                    size="sm"
                    className="gap-1.5 flex-1"
                    onClick={handleSave}
                    disabled={isSaving || isSavedAlready}
                  >
                    {isSavedAlready ? (
                      <BookmarkCheck className="h-3.5 w-3.5" />
                    ) : (
                      <Bookmark className="h-3.5 w-3.5" />
                    )}
                    {isSavedAlready
                      ? t("aiRecipe.video.saved", "已保存")
                      : t("aiRecipe.video.save", "保存")}
                  </Button>
                </div>

                {/* Recipe detail dialog with video generation */}
                <SavedRecipeDetailDialog
                  open={showRecipeDialog}
                  onOpenChange={setShowRecipeDialog}
                  recipe={recipe as any}
                  recipeName={getDisplayName(recipe)}
                  initialImageUrl={recipe.image_url}
                  onSave={!isSavedAlready ? () => handleSave() : undefined}
                  isSaving={isSaving}
                  isSaved={isSavedAlready}
                  enableVideoGeneration={!!recipe.image_url}
                />
              </div>
            ) : null}
          </div>
        </div>
      </div>
    </div>
  );
};

export default AIVideoGenerator;
